import{_ as t,c as i,a1 as a,o as c}from"./chunks/framework.BDxlaA_J.js";const u=JSON.parse('{"title":"Kỹ thuật Tạo Gói tin UDP và TCP bằng hping3","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/2-scanning-networks/1-hping3.md","filePath":"vi/categories/ethical-hacking-labs/2-scanning-networks/1-hping3.md"}'),e={name:"vi/categories/ethical-hacking-labs/2-scanning-networks/1-hping3.md"};function h(s,n,p,o,g,r){return c(),i("div",null,n[0]||(n[0]=[a(`<h1 id="ky-thuat-tao-goi-tin-udp-va-tcp-bang-hping3" tabindex="-1">Kỹ thuật Tạo Gói tin UDP và TCP bằng <code>hping3</code> <a class="header-anchor" href="#ky-thuat-tao-goi-tin-udp-va-tcp-bang-hping3" aria-label="Permalink to &quot;Kỹ thuật Tạo Gói tin UDP và TCP bằng \`hping3\`&quot;">​</a></h1><p>Hping3 là một chương trình có thể lập trình kịch bản sử dụng <a href="https://www.tcl.tk/about/language.html" target="_blank" rel="noreferrer">ngôn ngữ Tcl</a>, trong đó các gói tin có thể được nhận và gửi thông qua biểu diễn nhị phân hoặc chuỗi mô tả các gói tin.</p><p>Trong quá trình quét mạng, nhiệm vụ đầu tiên của bạn là quét mạng mục tiêu để xác định tất cả các cổng mở có thể, các máy chủ đang hoạt động và các dịch vụ đang chạy. Kiến thức về các kỹ thuật tạo gói tin có thể giúp bạn quét mạng vượt qua tường lửa hoặc IDS.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu: <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu:&quot;">​</a></h3><ul><li>Cách thực hiện quét mạng và tạo gói tin bằng các lệnh hping3.</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu: <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu:&quot;">​</a></h3><ul><li>Kali Linux (máy tấn công)</li><li>Windows 10 (máy mục tiêu)</li></ul><h2 id="tong-quan-ve-tao-goi-tin" tabindex="-1">Tổng quan về Tạo Gói tin <a class="header-anchor" href="#tong-quan-ve-tao-goi-tin" aria-label="Permalink to &quot;Tổng quan về Tạo Gói tin&quot;">​</a></h2><p>Tạo gói tin (Packet crafting) là một kỹ thuật cho phép bạn tìm các lỗ hổng hoặc điểm vào mạng mục tiêu. Điều này có thể được thực hiện bằng cách tạo các gói tin mạng tùy chỉnh để kiểm tra thiết bị mạng và hành vi.</p><hr><p><strong>Lưu ý:</strong> Trước khi bắt đầu bài lab này, hãy cài đặt Wireshark trên máy Windows 10.</p><h2 id="cac-lenh-co-ban-hping3" tabindex="-1">Các lệnh cơ bản hping3 <a class="header-anchor" href="#cac-lenh-co-ban-hping3" aria-label="Permalink to &quot;Các lệnh cơ bản hping3&quot;">​</a></h2><p>Đăng nhập vào Kali Linux và khởi động Terminal. Sử dụng <code>hping3 -h</code> để hiển thị tất cả các lệnh. Chúng ta sẽ tập trung vào một vài lệnh nên đừng lo lắng.</p><p>Bắt đầu nào!</p><p><code>hping3 -c 3 &lt;địa chỉ IP mục tiêu&gt;</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>...</span></span>
<span class="line"><span>3 packets transmitted, 3 packets received, 0% packet loss</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>Lưu ý ở cuối đầu ra, 3 gói tin đã được gửi và nhận. Bạn sẽ nhận được phản hồi này.</p><p><code>-c</code> đại diện cho số lượng gói tin. Có nghĩa là chúng ta chỉ muốn gửi ba gói tin đến máy mục tiêu.</p><p>Tiếp theo chúng ta sẽ gửi một quét cờ SYN với một phạm vi cổng.</p><p><code>hping3 --scan 1-3000 -S &lt;địa chỉ IP mục tiêu&gt;</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Scanning 10.0.2.15 (10.0.2.15), port 1-3000</span></span>
<span class="line"><span>3000 ports to scan, use -V to see all the replies</span></span>
<span class="line"><span>+----+-----------+---------+---+-----+-----+-----+</span></span>
<span class="line"><span>|port| serv name |  flags  |ttl| id  | win | len |</span></span>
<span class="line"><span>+----+-----------+---------+---+-----+-----+-----+</span></span>
<span class="line"><span>  135 epmap      : .S..A... 128 62018 65392    46</span></span>
<span class="line"><span>  139 netbios-ssn: .S..A... 128 63042  8192    46</span></span>
<span class="line"><span>  445 microsoft-d: .S..A... 128 52291 65392    46</span></span>
<span class="line"><span>All replies received. Done.</span></span>
<span class="line"><span>Not responding ports:</span></span></code></pre></div><p>Tham số <code>--scan</code> xác định phạm vi cổng để quét. <code>-S</code> đại diện cho <strong>cờ SYN</strong>.</p><p>Đầu ra cho thấy các cổng mở trên máy mục tiêu, tức là Windows 10.</p><h2 id="tao-goi-tin-udp" tabindex="-1">Tạo gói tin UDP <a class="header-anchor" href="#tao-goi-tin-udp" aria-label="Permalink to &quot;Tạo gói tin UDP&quot;">​</a></h2><p>Để thực hiện tạo gói tin UDP trên máy mục tiêu, gõ:</p><p><code>hping3 &lt;địa chỉ IP mục tiêu&gt; --udp --rand-source --data 500</code></p><p>Tiếp theo chuyển sang máy Windows 10 và khởi động Wireshark để bắt đầu bắt gói tin.</p><p>Quan sát các gói tin UDP và ICMP. Nhấp vào gói tin <strong>UDP</strong> và quan sát bên trong, <strong>Data (500 bytes)</strong>.</p><p><code>--udp</code> Chế độ UDP. <code>--rand-source</code> Tùy chọn này bật chế độ nguồn ngẫu nhiên. hping sẽ gửi các gói tin với địa chỉ nguồn ngẫu nhiên. <code>--data</code> kích thước dữ liệu tính bằng byte.</p><h2 id="gui-yeu-cau-tcp-syn" tabindex="-1">Gửi Yêu cầu TCP SYN <a class="header-anchor" href="#gui-yeu-cau-tcp-syn" aria-label="Permalink to &quot;Gửi Yêu cầu TCP SYN&quot;">​</a></h2><p>Khởi động Wireshark trên máy Windows một lần nữa và để nó chạy.</p><p>Để gửi yêu cầu TCP SYN đến máy mục tiêu, gõ:</p><p><code>hping3 -S &lt;địa chỉ IP mục tiêu&gt; -p 80 -c 5</code></p><p><strong>Điều này sẽ truyền 5 gói tin yêu cầu đến máy nạn nhân thông qua cổng 80.</strong></p><p><code>-S</code> sẽ thực hiện yêu cầu TCP SYN trên mục tiêu, <code>-p</code> sẽ truyền lưu lượng qua cổng được chỉ định, và <code>-c</code> là số lượng gói tin gửi đến máy mục tiêu.</p><p>Chuyển sang máy mục tiêu (Windows), và quan sát các gói tin TCP được bắt trong Wireshark.</p><p>Tiếp theo, dừng bắt gói tin, và bắt đầu bắt gói tin mới. Để Wireshark chạy tiếp.</p><h2 id="thuc-hien-tcp-flooding" tabindex="-1">Thực hiện TCP Flooding <a class="header-anchor" href="#thuc-hien-tcp-flooding" aria-label="Permalink to &quot;Thực hiện TCP Flooding&quot;">​</a></h2><p><code>hping3 &lt;địa chỉ IP mục tiêu&gt; --flood</code></p><p><code>--flood</code> gửi gói tin nhanh nhất có thể, mà không cần quan tâm đến việc hiển thị các phản hồi đến.</p><p>Sau vài giây dừng bắt gói tin trong Wireshark trên Windows. Bạn sẽ nhận thấy cuộc tấn công TCP flooding từ máy tấn công.</p><p>Lưu ý: Nếu bạn muốn kiểm tra luồng gói tin TCP và thực hiện một số kỹ thuật reverse engineering, hãy đảm bảo hiểu nhiều hơn là bắt tay ba bước nổi tiếng.</p><hr><p>Một số liên kết thú vị:</p><p><a href="https://packetlife.net/blog/2010/jun/7/understanding-tcp-sequence-acknowledgment-numbers/" target="_blank" rel="noreferrer">Số thứ tự và Xác nhận TCP</a></p><p><a href="https://www.gkbrk.com/2016/05/hotel-music/" target="_blank" rel="noreferrer">Reverse Engineering Một Luồng UDP Bí ẩn Trong Khách Sạn Của Tôi</a></p><p><a href="http://www.tcpipguide.com/free/index.htm" target="_blank" rel="noreferrer">Hướng dẫn TCP/IP</a></p>`,47)]))}const d=t(e,[["render",h]]);export{u as __pageData,d as default};
